import React from 'react';
import { Tabs, Tab, IconButton, Menu, MenuItem, Dialog, DialogTitle, DialogContent, TextField, DialogActions, Button } from '@mui/material';
import MoreVertIcon from '@mui/icons-material/MoreVert';

const ChatTabs = ({
    chatTabs,
    currentTabIndex,
    handleTabChange,
    handleNewChat,
    handleMenuOpen,
    handleMenuClose,
    menuAnchorEl,
    tabToEdit,
    handleDeleteTab,
    handleRenameTab,
    renameDialogOpen,
    renameValue,
    setRenameValue,
    handleRenameDialogSave,
    handleRenameDialogClose,
}) => {
    return (
        <>
            <Tabs value={currentTabIndex} onChange={handleTabChange}>
                {chatTabs.map((tab, index) => (
                    <Tab
                        key={tab.id}
                        label={tab.label}
                        icon={
                            <IconButton
                                size="small"
                                onClick={(event) => {
                                    event.stopPropagation();
                                    handleMenuOpen(event, tab);
                                }}
                            >
                                <MoreVertIcon />
                            </IconButton>
                        }
                        iconPosition="end"
                    />
                ))}
                <Tab label="+" onClick={handleNewChat} />
            </Tabs>

            <Menu
                anchorEl={menuAnchorEl}
                open={Boolean(menuAnchorEl)}
                onClose={handleMenuClose}
            >
                <MenuItem onClick={handleRenameTab}>Rename</MenuItem>
                <MenuItem onClick={handleDeleteTab}>Delete</MenuItem>
            </Menu>

            <Dialog open={renameDialogOpen} onClose={handleRenameDialogClose}>
                <DialogTitle>Rename Chat</DialogTitle>
                <DialogContent>
                    <TextField
                        autoFocus
                        margin="dense"
                        label="Chat Name"
                        fullWidth
                        value={renameValue}
                        onChange={(e) => setRenameValue(e.target.value)}
                    />
                </DialogContent>
                <DialogActions>
                    <Button onClick={handleRenameDialogClose}>Cancel</Button>
                    <Button onClick={handleRenameDialogSave}>Save</Button>
                </DialogActions>
            </Dialog>
        </>
    );
};

export default ChatTabs;
